import {
  createContext,
  useCallback,
  useContext,
  useMemo,
  useState
} from 'react';
import { authService } from '../services/authService';

const AuthContext = createContext(undefined);

const STORAGE_KEY = 'wn:auth';

const getStoredAuth = () => {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (!raw) return { user: null, token: null };
    const parsed = JSON.parse(raw);
    return {
      user: parsed.user || null,
      token: parsed.token || null
    };
  } catch (error) {
    console.warn('Failed to parse auth storage', error);
    return { user: null, token: null };
  }
};

export const AuthProvider = ({ children }) => {
  const [authState, setAuthState] = useState(() => getStoredAuth());
  const [isProcessing, setIsProcessing] = useState(false);

  const persistAuth = useCallback((nextAuth) => {
    setAuthState(nextAuth);
    if (nextAuth.token && nextAuth.user) {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(nextAuth));
    } else {
      localStorage.removeItem(STORAGE_KEY);
    }
  }, []);

  const login = useCallback(
    async (credentials) => {
      setIsProcessing(true);
      try {
        const response = await authService.login(credentials);
        persistAuth({ user: response.user, token: response.token });
        return response.user;
      } catch (error) {
        throw error;
      } finally {
        setIsProcessing(false);
      }
    },
    [persistAuth]
  );

  const register = useCallback(
    async (payload) => {
      setIsProcessing(true);
      try {
        const response = await authService.register(payload);
        persistAuth({ user: response.user, token: response.token });
        return response.user;
      } catch (error) {
        throw error;
      } finally {
        setIsProcessing(false);
      }
    },
    [persistAuth]
  );

  const logout = useCallback(() => {
    persistAuth({ user: null, token: null });
  }, [persistAuth]);

  const value = useMemo(
    () => ({
      user: authState.user,
      token: authState.token,
      isAuthenticated: Boolean(authState.token),
      isProcessing,
      login,
      register,
      logout
    }),
    [authState, isProcessing, login, register, logout]
  );

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
};

export const useAuthContext = () => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuthContext must be used within an AuthProvider');
  }
  return context;
};
